// adaptiveLimiter provides proactive rate limiting with adaptive ceiling discovery.
type adaptiveLimiter struct {
	mu          sync.Mutex
	rate        float64
	floor       float64
	ceiling     float64
	successes   int
	rampAfter   int
	lastRequest time.Time
}

func newAdaptiveLimiter(ratePerSec float64) *adaptiveLimiter {
	if ratePerSec <= 0 {
		return nil
	}
	return &adaptiveLimiter{
		rate:      ratePerSec,
		floor:     ratePerSec,
		rampAfter: 10,
	}
}

func (l *adaptiveLimiter) Wait() {
	if l == nil {
		return
	}
	l.mu.Lock()
	delay := time.Duration(float64(time.Second) / l.rate)
	elapsed := time.Since(l.lastRequest)
	l.mu.Unlock()
	if elapsed < delay {
		time.Sleep(delay - elapsed)
	}
	l.mu.Lock()
	l.lastRequest = time.Now()
	l.mu.Unlock()
}

func (l *adaptiveLimiter) OnSuccess() {
	if l == nil {
		return
	}
	l.mu.Lock()
	defer l.mu.Unlock()
	l.successes++
	if l.successes >= l.rampAfter {
		newRate := l.rate * 1.25
		if l.ceiling > 0 && newRate > l.ceiling*0.9 {
			newRate = l.ceiling * 0.9
		}
		l.rate = newRate
		l.successes = 0
	}
}

func (l *adaptiveLimiter) OnRateLimit() {
	if l == nil {
		return
	}
	l.mu.Lock()
	defer l.mu.Unlock()
	l.ceiling = l.rate
	l.rate = l.rate / 2
	if l.rate < 0.5 {
		l.rate = 0.5
	}
	l.successes = 0
}

func (l *adaptiveLimiter) Rate() float64 {
	if l == nil {
		return 0
	}
	l.mu.Lock()
	defer l.mu.Unlock()
	return l.rate
}

